12	// TestConcentratorRoamRebindsPeerOnAuthenticatedProbe is the T90 acceptance for per-peer
13	// NAT/roaming on a shared concentrator socket. It mirrors the single-peer re-roam discipline
14	// (D11/T16, TestMultipathReRoamRelearnsRemoteVirtStable) at the per-peer demux layer:
15	//
16	//   - Peer B is bound to its ORIGINAL source by an authenticated PROBE; peer A (the primary)
17	//     is bound to its own source likewise.
18	//   - Peer B roams: its traffic now arrives from a NEW, not-yet-bound source. B's DATA from
19	//     that new source is DROPPED — a binding, like a return remote, is learned ONLY from an
20	//     authenticated PROBE (D9/D11), never from forgeable DATA. Critically the dropped DATA is
21	//     never MISROUTED into peer A's resequencer.
22	//   - A fresh authenticated PROBE under B's psk from the new source RE-BINDS the new source to
23	//     the SAME peer B; thereafter DATA from the new source routes to B's resequencer.
24	//   - Throughout, peer A's resequencer observes ONLY peer A's own frames — none of B's, before,
25	//     during, or after the roam.
26	//
27	// It drives demuxInbound directly (no goroutines), like source_bind_test.go / roam_test.go.
28	func TestConcentratorRoamRebindsPeerOnAuthenticatedProbe(t *testing.T) {
29		pskA := testKey(t, 0x11) // primary == peer A
30		pskB := testKey(t, 0x22) // peer B
31		clk := newFakeClock()
32	
33		m, primary, second := twoPeerConcentrator(t, pskA, pskB)
34		aView := m.paths[0] // the primary's (peer A's) view of shared socket "a" — what the reader hands demuxInbound
35		bView := peerPathByName(second, "a")
36		if bView == nil {
37			t.Fatal("peer B has no view of shared path 'a'")
38		}
39	
40		dataCodecA, _ := frame.NewCodec(pskA)
41		dataCodecB, _ := frame.NewCodec(pskB)
42		dataA := func(seq uint64, payload string) []byte {
43			raw, err := dataCodecA.Encode(nil, frame.Data{OuterSeq: seq, PathID: aView.id, Payload: []byte(payload)})
44			if err != nil {
45				t.Fatalf("encode peer-A data: %v", err)
46			}
47			return raw
48		}
49		dataB := func(seq uint64, payload string) []byte {
50			raw, err := dataCodecB.Encode(nil, frame.Data{OuterSeq: seq, PathID: bView.id, Payload: []byte(payload)})
51			if err != nil {
52				t.Fatalf("encode peer-B data: %v", err)
53			}
54			return raw
55		}
56		probeUnder := func(psk config.Key, pathID uint8, seq uint64) []byte {
57			raw, err := frame.Encode(psk, frame.Probe{PathID: pathID, ProbeSeq: seq, TimestampNanos: clk.Now().UnixNano(), IsEcho: false})
58			if err != nil {
59				t.Fatalf("encode probe: %v", err)
60			}
61			return raw
62		}
63	
64		srcA := netip.MustParseAddrPort("198.51.100.10:5000") // peer A's source
65		srcB0 := netip.MustParseAddrPort("203.0.113.20:6000") // peer B's ORIGINAL source
66		srcB1 := netip.MustParseAddrPort("192.0.2.30:7000")   // peer B's source AFTER the roam (a NEW, unbound addr)
67	
68		// --- bind both peers via authenticated PROBEs on the shared socket ---
69		m.demuxInbound(aView, probeUnder(pskA, aView.id, 1), srcA)
70		if bound, ok := m.lookupPeerBySource(srcA.Addr()); !ok || bound != primary {
71			t.Fatalf("srcA bound to %v (ok=%v), want peer A (primary)", bound, ok)
72		}
73		m.demuxInbound(aView, probeUnder(pskB, bView.id, 1), srcB0)
74		if bound, ok := m.lookupPeerBySource(srcB0.Addr()); !ok || bound != second {
75			t.Fatalf("srcB0 bound to %v (ok=%v), want peer B", bound, ok)
76		}
77	
78		// Pre-roam: peer A's own DATA routes to peer A. (First frame the primary's resequencer sees.)
79		m.demuxInbound(aView, dataA(10, "a-pre"), srcA)
80	
81		// --- the roam: peer B's traffic now appears from srcB1 (a NEW, unbound source) ---
82		// B's DATA from the new source must be DROPPED until an authenticated PROBE re-binds it, and
83		// must NOT be misrouted into peer A's resequencer.
84		m.demuxInbound(aView, dataB(20, "b-roam-early"), srcB1)
85		if _, ok := m.lookupPeerBySource(srcB1.Addr()); ok {
86			t.Fatal("DATA from the roamed (unbound) source established a source->peer binding — only a PROBE may (D9/D11)")
87		}
88		if it, ok := second.resequencer.Load().Pop(); ok {
89			t.Fatalf("peer B's DATA from an unbound roamed source was delivered before any re-binding PROBE (%q)", it.Payload)
90		}
91	
92		// A fresh authenticated PROBE under peer B's psk from the NEW source re-binds it to the SAME peer B.
93		m.demuxInbound(aView, probeUnder(pskB, bView.id, 2), srcB1)
94		bound, ok := m.lookupPeerBySource(srcB1.Addr())
95		if !ok {
96			t.Fatal("an authenticated PROBE from the roamed source did not re-bind it")
97		}
98		if bound != second {
99			t.Fatalf("roamed source re-bound to the wrong peer: got %v, want peer B", bound)
100		}
101		// Peer B's view learned the new source as its return remote (authenticated re-learn, D11).
102		if remote, ok := bView.getRemote(); !ok || remote != srcB1 {
103			t.Fatalf("peer B view remote after roam = %v (ok=%v), want %v", remote, ok, srcB1)
