110		} else if it.Src != srcB1 {
111			t.Fatalf("peer B's post-roam frame carried src %v, want %v", it.Src, srcB1)
112		}
113	
114		// Peer A's own DATA still routes to peer A after the roam churn.
115		m.demuxInbound(aView, dataA(11, "a-post"), srcA)
116	
117		// --- invariant: peer A's resequencer observed ONLY peer A's own frames, never any of B's. ---
118		rqA := primary.resequencer.Load()
119		var gotA [][]byte
120		for {
121			it, ok := rqA.Pop()
122			if !ok {
123				break
124			}
125			gotA = append(gotA, append([]byte(nil), it.Payload...))
126		}
127		wantA := [][]byte{[]byte("a-pre"), []byte("a-post")}
128		if len(gotA) != len(wantA) {
129			t.Fatalf("peer A resequencer delivered %d frame(s) %q, want exactly %q", len(gotA), gotA, wantA)
130		}
131		for i := range wantA {
132			if !bytes.Equal(gotA[i], wantA[i]) {
133				t.Fatalf("peer A frame %d = %q, want %q", i, gotA[i], wantA[i])
134			}
135		}
136		for _, p := range gotA {
137			if bytes.Equal(p, []byte("b-roam-early")) || bytes.Equal(p, []byte("b-roam-late")) {
